import React, { Fragment, useState } from 'react';
import { useNavigate } from 'react-router-dom'; // Import useNavigate for programmatic navigation
import All_products_Customer from './All_products_Customer'; // Import the All_products_Customer component

const Home_Customer = ({ isAuthenticated, setAuth }) => {
  const navigate = useNavigate(); // Initialize the navigate function

  const handleLogout = () => {
    setAuth(false);
    navigate('/'); // Redirect to default Home page after logout
  };

  // If user is not authenticated, do not render the component
  if (!isAuthenticated) {
    return null;
  }

  return (
    <Fragment>
      {/* Title Bar */}
      <div className="title-bar">
        <h1>Shohojog</h1>
        <div className="logout-option">
          <button onClick={handleLogout}>Log out</button>
        </div>
      </div>

      {/* All Products for Customer */}
      <All_products_Customer /> {/* Render the All_products_Customer component */}
    </Fragment>
  );
};

export default Home_Customer;
